async function apiGet(path) {
  const url = `${_apiBaseUrl}${path}`
  const headers = { Authorization: `Bearer ${_apiToken}` }
  // O sandbox do Code node do n8n normalmente NÃO expõe `fetch`; usa o helper HTTP nativo.
  try {
    if (_httpCtx && _httpCtx.helpers && typeof _httpCtx.helpers.httpRequest === 'function') {
      return await _httpCtx.helpers.httpRequest({ method: 'GET', url, headers, json: true, timeout: 8000 })
    }
  } catch (e) { /* cai no fetch abaixo */ }
  // Fallback p/ ambientes com fetch nativo (bun/Node, harness de teste)
  try {
    if (typeof fetch !== 'undefined') {
      const opts = { headers }
      if (typeof AbortSignal !== 'undefined' && AbortSignal.timeout) opts.signal = AbortSignal.timeout(8000)
      const r = await fetch(url, opts)
      return r.ok ? await r.json() : null
    }
  } catch (e) { /* ignore */ }
  return null
}
