function askQuestion(q) {
  if (q.t === 'entrada_choice') {
    return { response: q.q + '\n\n_Escolha uma das opções ou *digite o valor* em reais._' }
  }
  if (q.t === 'choice') {
    if (q.opts.length > 3) {
      return { response: q.q, interactive: makeList(q.q, q.opts.map(function(o){ return { id:o[0], title:o[1] } }), { button:'Ver opções', section:'Opções' }) }
    }
    return { response: q.q, interactive: makeButtons(q.q, q.opts.map(function(o){ return [o[0], o[1]] })) }
  }
  return { response: q.q }
}

function parseAnswer(q, incoming, rawText) {
  if (q.t === 'choice') {
    const found = q.opts.find(function(o){ return o[0] === incoming })
    if (!found) return { ok:false, err:'Por favor, escolha uma das opções. 👆' }
    return { ok:true, value: found[0] }
  }
  if (q.t === 'entrada_choice') {
    if (incoming === 'outro') return { ok: true, value: 'outro' }
    const v = parseMoney(rawText)
    if (isNaN(v) || v <= 0) return { ok: false, err: '❌ Valor inválido. Informe um número positivo (ex: 80000) ou escolha uma das opções acima.' }
    return { ok: true, value: v }
  }
  if (q.t === 'money') {
    const v = parseMoney(rawText)
    if (isNaN(v) || v <= 0) return { ok:false, err:'❌ Valor inválido. Informe um número positivo (ex: 250000).' }
    return { ok:true, value: v }
  }
  if (q.t === 'int') {
    const v = parseInt((rawText||'').replace(/\D/g,''))
    if (isNaN(v) || v < 0) return { ok:false, err:'Informe um número (0 se não tiver).' }
    return { ok:true, value: v }
  }
  if (q.t === 'date') {
    const m = (rawText||'').trim().match(/^(\d{2})\/(\d{2})\/(\d{4})$/)
    if (!m) return { ok:false, err:'Data inválida. Use DD/MM/AAAA.' }
    return { ok:true, value: rawText.trim() }
  }
  if (q.t === 'cpf') {
    if (!isValidCPF(incoming)) return { ok:false, err:'CPF inválido. Informe os 11 dígitos.' }
    return { ok:true, value: incoming.replace(/\D/g,'') }
  }
  const t = (rawText||'').trim()
  if (!t) return { ok:false, err:'Por favor, responda.' }
  return { ok:true, value: titleCase(t) }
}

function nextStep(flow, c, fromIdx) {
  const qs = FLOWS[flow].q
  for (let i = fromIdx; i < qs.length; i++) {
    const v = c[qs[i].k]
    if (v === undefined || v === null || v === '') return i
  }
  return qs.length
}

function handoff(flow, c) {
  const label = FLOWS[flow] ? FLOWS[flow].label : 'Atendimento'
  return {
    response: `✅ Obrigado pelas informações! 😊\n\nEstamos encaminhando seu atendimento (*${label}*) para um de nossos especialistas, que dará continuidade ao processo.\n\nAguarde alguns instantes. ⏳`,
    newState: 'human_handoff',
    ctx: { ...c, requestedProduct: label },
    triggerHandoff: true,
    clientPayload: { whatsappNumber: phone, name: c.name, cpf: c.cpf, city: c.cidade },
  }
}

function startFlow(flow, c) {
  const idx = nextStep(flow, c, 0)
  if (idx >= FLOWS[flow].q.length) return handoff(flow, c)
  const ask = askQuestion(FLOWS[flow].q[idx])
  return { ...ask, newState: 'in_flow', ctx: { ...c, flow, step: idx } }
}

