  else if (incoming === '3') result = startFlow('hab_terreno', ctx)
  else result = { response: 'Escolha 1, 2 ou 3. 👆', interactive: HAB_SUBMENU, newState: 'awaiting_hab_type', ctx }
}

// ── Motor de coleta ──
if (!result && currentState === 'in_flow') {
  const flow = ctx.flow
  const step = ctx.step
  if (!flow || !FLOWS[flow] || typeof step !== 'number') {
    result = { response: 'Vamos recomeçar. 🙂', interactive: mainMenu(), newState: 'awaiting_menu', ctx: {} }
  } else {
    const q = FLOWS[flow].q[step]
    const ans = parseAnswer(q, incoming, rawText)
    if (!ans.ok) {
      const ask = askQuestion(q)
      result = { response: `${ans.err}\n\n${ask.response}`, interactive: ask.interactive, newState: 'in_flow', ctx }
    } else {
      const newCtx = { ...ctx, [q.k]: ans.value }
      // Se entradaEscolha foi um valor numérico (não 'outro'), propaga para `entrada`
      // e o nextStep vai pular a pergunta manual automaticamente (já preenchida)
      if (q.k === 'entradaEscolha' && ans.value !== 'outro') {
        if (newCtx.valorImovel && ans.value < newCtx.valorImovel * 0.20) {
          const minEntrada = Math.round(newCtx.valorImovel * 0.20)
          const imovel = newCtx.valorImovel
          const p20 = Math.round(imovel * 0.20)
          const p25 = Math.round(imovel * 0.25)
          const p30 = Math.round(imovel * 0.30)
          const rows = [
            { id: String(p20), title: `20% — ${fmt(p20)}`, description: 'Mínimo exigido (SFH)' },
            { id: String(p25), title: `25% — ${fmt(p25)}` },
            { id: String(p30), title: `30% — ${fmt(p30)}` },
            { id: 'outro', title: '✏️ Digitar valor' },
          ]
          result = { response: `❌ Entrada insuficiente. O mínimo é *20%* = *${fmt(minEntrada)}*.\n\nEscolha uma opção ou informe um valor maior:`, interactive: makeList('Qual o *valor de entrada*?', rows, { button: 'Ver opções', section: 'Opções de entrada' }), newState: 'in_flow', ctx }
        } else {
          newCtx.entrada = ans.value
        }
      }
      // Entrada mínima: 20% do valor do imóvel (SFH)
      if (q.k === 'entrada' && newCtx.valorImovel && ans.value < newCtx.valorImovel * 0.20) {
        const minEntrada = newCtx.valorImovel * 0.20
        const ask = askQuestion(q)
        result = { response: `❌ Entrada insuficiente. O mínimo para o SFH é *20%* do imóvel = *${fmt(minEntrada)}*.\n\n${ask.response}`, interactive: ask.interactive, newState: 'in_flow', ctx }
      }
      if (!result) {
        const nextIdx = nextStep(flow, newCtx, step + 1)
        if (nextIdx >= FLOWS[flow].q.length) {
          if (flow === 'hab_pronto' && newCtx.valorImovel && newCtx.entrada && newCtx.prazoMeses) {
            const applicantAge = newCtx.nascimento ? calcAge(newCtx.nascimento) : 35
            const prazo = parseInt(newCtx.prazoMeses)
            result = {
              response: '⏳ Calculando sua simulação Caixa... Aguarde!',
              newState: 'awaiting_post_sim_hab',
              ctx: newCtx,
              triggerSimulation: true,
              simulationPayload: {
                whatsappNumber: phone,
                financingType: 'imobiliario',
                requestedAmount: newCtx.valorImovel,
                downPaymentAmount: newCtx.entrada,
                termMonths: prazo,
                propertyValue: newCtx.valorImovel,
                monthlyIncome: newCtx.rendaFamiliar,
                applicantAgeYears: applicantAge,
              },
            }
          } else if (flow === 'hab_construcao' && newCtx.valorTerreno && newCtx.valorConstrucao && newCtx.prazoMeses) {
            const applicantAge = newCtx.nascimento ? calcAge(newCtx.nascimento) : 35
            const propertyValue = newCtx.valorTerreno + newCtx.valorConstrucao
            const requestedAmount = propertyValue
            const downPaymentAmount = newCtx.valorTerreno + Math.round(newCtx.valorConstrucao * 0.20)
            // financedAmount = 80% do custo da construção (regra Caixa SFH)
            result = {
              response: '⏳ Calculando sua simulação... Aguarde!',
              newState: 'awaiting_post_sim_hab',
              ctx: newCtx,
              triggerSimulation: true,
              simulationPayload: {
                whatsappNumber: phone,
                financingType: 'imobiliario',
                requestedAmount,
                downPaymentAmount,
                termMonths: parseInt(newCtx.prazoMeses),
                propertyValue,
                monthlyIncome: newCtx.rendaFamiliar,
                applicantAgeYears: applicantAge,
              },
            }
          } else if (flow === 'hab_terreno' && newCtx.valorTerreno && newCtx.prazoMeses) {
            const applicantAge = newCtx.nascimento ? calcAge(newCtx.nascimento) : 35
            const propertyValue = newCtx.valorTerreno
            const requestedAmount = propertyValue
            const downPaymentAmount = Math.round(propertyValue * 0.40)
            // financedAmount = 60% do valor do terreno (LTV máx Caixa para terreno)
            result = {
              response: '⏳ Calculando sua simulação... Aguarde!',
              newState: 'awaiting_post_sim_hab',
              ctx: newCtx,
              triggerSimulation: true,
              simulationPayload: {
                whatsappNumber: phone,
                financingType: 'imobiliario',
                requestedAmount,
                downPaymentAmount,
                termMonths: parseInt(newCtx.prazoMeses),
                propertyValue,
                monthlyIncome: newCtx.rendaFamiliar,
                applicantAgeYears: applicantAge,
              },
            }
          } else {
            result = handoff(flow, newCtx)
          }
        } else {
          const nextQ = FLOWS[flow].q[nextIdx]
          if (nextQ.t === 'entrada_choice' && newCtx.valorImovel) {
            const imovel = newCtx.valorImovel
            const p20 = Math.round(imovel * 0.20)
            const p25 = Math.round(imovel * 0.25)
            const p30 = Math.round(imovel * 0.30)
            const rows = [
              { id: String(p20), title: `20% — ${fmt(p20)}`, description: 'Mínimo exigido (SFH)' },
              { id: String(p25), title: `25% — ${fmt(p25)}` },
              { id: String(p30), title: `30% — ${fmt(p30)}` },
              { id: 'outro', title: '✏️ Digitar valor' },
            ]
            result = { response: nextQ.q, interactive: makeList(nextQ.q, rows, { button: 'Ver opções', section: 'Opções de entrada' }), newState: 'in_flow', ctx: { ...newCtx, step: nextIdx } }
          } else {
            const ask = askQuestion(nextQ)
            result = { ...ask, newState: 'in_flow', ctx: { ...newCtx, step: nextIdx } }
          }
        }
      }
    }
  }
}

// ── Pós-simulação habitacional ──
if (!result && currentState === 'awaiting_post_sim_hab') {
  if (incoming === '1') {
    const handoffCtx = { ...ctx, requestedProduct: 'Habitacional — Simulação Caixa' }
    result = { response: 'Perfeito! 😊 Encaminhando para um especialista. Aguarde! ⏳', newState: 'human_handoff', ctx: handoffCtx, triggerHandoff: true, clientPayload: { whatsappNumber: phone, name: ctx.name } }
  } else if (incoming === '2') {
    result = { response: 'Sem problemas! 😊 Estaremos aqui sempre que precisar.\n\nEnvie "menu" para outras opções.', newState: 'completed', ctx: {} }
  } else if (isGreeting || isRestart) {
    result = { response: 'Olá! 👋', interactive: mainMenu(), newState: 'awaiting_menu', ctx: {} }
  } else {
    result = { response: 'Responda com:\n\n1️⃣ Sim, quero falar com um especialista\n2️⃣ Não, obrigado', newState: 'awaiting_post_sim_hab', ctx }
  }
}

// ── Pós-handoff ──
if (!result && currentState === 'human_handoff') {
  if (isGreeting) {
    result = { response: 'Olá! 👋', interactive: mainMenu(), newState: 'awaiting_menu', ctx: {} }
  } else {
    result = { response: 'Seu atendimento já está com um de nossos especialistas. Aguarde o contato, por favor. 😊', newState: 'human_handoff', ctx }
  }
}

// ── Concluído / fallback ──
if (!result && currentState === 'completed') {
  result = { response: 'Olá! 👋', interactive: mainMenu(), newState: 'awaiting_menu', ctx: {} }
}
if (!result) {
  result = { response: 'Não entendi. 😅 Veja as opções:', interactive: mainMenu(), newState: 'awaiting_menu', ctx: {} }
}

// Inject API config for downstream HTTP Request nodes
const _result = result ?? { response: msgData.response, newState: currentState, ctx }
const finalOutput = {
  phone,
  phoneNumberId,
  ..._result,
  newContext: _result.ctx ?? _result.newContext ?? ctx,
  _apiBaseUrl,
  _apiToken,
}
return [{ json: finalOutput }]
})()

const routerData = $('Roteador de Conversa').first().json
const sim = $input.first().json
const ctx = routerData.newContext || {}

const formatBRL = v => new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(v)
const fmtRate = r => (r * 100).toFixed(2).replace('.', ',')

const PERSON_PT = { pf: 'Pessoa Física', pj: 'Pessoa Jurídica' }
const CIVIL_PT = { single:'Solteiro(a)', married:'Casado(a)', divorced:'Divorciado(a)', widowed:'Viúvo(a)', stable_union:'União estável' }
const FUEL_PT = { flex:'Flex', gasoline:'Gasolina', diesel:'Diesel', electric:'Elétrico', hybrid:'Híbrido' }

const isVeiculo = (ctx.financingType ?? ctx.financiamento_tipo) === 'veiculo'

let text = routerData.response + '\n\n'

if (sim?.results?.length > 0) {
  const financedAmount = sim.financedAmount ?? 0
  const termMonths = sim.termMonths ?? 0

  // ── Perfil do solicitante ──
  const userLines = []
  if (ctx.name) userLines.push(`👤 *${ctx.name}*`)
  const perfilBits = []
  if (ctx.personType && PERSON_PT[ctx.personType]) perfilBits.push(PERSON_PT[ctx.personType])
  if (ctx.civilStatus && CIVIL_PT[ctx.civilStatus]) perfilBits.push(CIVIL_PT[ctx.civilStatus])
  if (perfilBits.length) userLines.push(`   ${perfilBits.join(' • ')}`)
  if (ctx.city && ctx.state) userLines.push(`   📍 ${ctx.city}/${ctx.state}`)
  if (ctx.monthlyIncome) userLines.push(`   💵 Renda: ${formatBRL(Number(ctx.monthlyIncome))}`)
  if (userLines.length) text += userLines.join('\n') + '\n\n'

  // ── Veículo pretendido (FIPE) ──
  if (isVeiculo) {
    const modelo = ctx.fipeModelo || ctx.vehicleModel || ''
    const marca = ctx.vehicleBrand || ''
    const fuelPt = (ctx.vehicleFuel && FUEL_PT[ctx.vehicleFuel]) ? FUEL_PT[ctx.vehicleFuel] : ''
    text += `🚗 *Veículo pretendido:*\n`
    text += `   ${`${marca} ${modelo}`.trim()}${ctx.vehicleYear ? ` — ${ctx.vehicleYear}` : ''}${fuelPt ? ` (${fuelPt})` : ''}\n`
    if (ctx.fipeCodigo) text += `   🔢 Código FIPE: ${ctx.fipeCodigo}\n`
    if (ctx.fipePreco) text += `   💰 Tabela FIPE: ${ctx.fipePreco}${ctx.fipeMesRef ? ` (ref. ${ctx.fipeMesRef})` : ''}\n`
    if (ctx.fipeUrl) text += `   🔗 Consulta oficial: ${ctx.fipeUrl}\n`
    text += '\n'
  }

  text += `💰 *Valor financiado:* ${formatBRL(financedAmount)} em *${termMonths} parcelas*\n`
  if (sim.fipeValue) {
    const ltv = sim.fipeLtv ? (sim.fipeLtv * 100).toFixed(0) : '?'
    text += `🔍 *Valor FIPE:* ${formatBRL(sim.fipeValue)} | LTV: ${ltv}%`
    if (sim.fipeLtv > 1.0) text += ` ⚠️ _acima do valor FIPE_`
    text += `\n`
  }
  if (sim.marketBaseRateAnnual) {
    text += `📈 _Base de mercado BCB: ${sim.marketBaseRateAnnual.toFixed(1)}% a.a. (taxa média CDC veículos)_\n`
  }
  text += '📊 *Resultados da Simulação*\n\n'

  const medals = ['🥇','🥈','🥉','4️⃣','5️⃣']
  sim.results.slice(0,5).forEach((r, i) => {
    text += `${medals[i]} *${r.bankName}*\n`
    if (r.caixaMcmv) {
      const mcmv = r.caixaMcmv
      const isMcmvFaixa = mcmv.mcmvFaixa <= 6
      if (isMcmvFaixa) text += `   ✅ *Minha Casa Minha Vida — Faixa ${mcmv.mcmvFaixa}*\n`
      else text += `   🏦 *Financiamento Habitacional — Faixa ${mcmv.mcmvFaixa}*\n`
      text += `   Taxa: ${fmtRate(r.rateAnnual)}% a.a. | ${mcmv.effectiveTermMonths} parcelas\n`
      text += `   📌 SAC — 1ª: ${formatBRL(r.sac.firstInstallment)} → última: ${formatBRL(r.sac.lastInstallment)}\n`
      text += `   Seguros: MIP ${formatBRL(mcmv.totalMip)} + DFI ${formatBRL(mcmv.totalDfi)} + TAC ${formatBRL(mcmv.tac)}\n`
      text += `   Total pago: ${formatBRL(r.sac.totalCost)}\n`
      if (mcmv.incomeCommitmentPercent > 30) {
        text += `   ⚠️ _Parcela inicial compromete ${mcmv.incomeCommitmentPercent.toFixed(0)}% da renda — Caixa pode pedir renda complementar_\n`
      }
      text += '\n'
    } else {
      text += `   Taxa: ${fmtRate(r.rateAnnual)}% a.a. | ${termMonths} parcelas\n`
      if (isVeiculo) {
        text += `   📌 PRICE — ${formatBRL(r.price.fixedInstallment)}/mês (parcela fixa)\n`
        text += `   SAC — 1ª: ${formatBRL(r.sac.firstInstallment)} → última: ${formatBRL(r.sac.lastInstallment)}\n`
      } else {
        text += `   📌 SAC — 1ª: ${formatBRL(r.sac.firstInstallment)} → última: ${formatBRL(r.sac.lastInstallment)}\n`
        if (r.price) text += `   PRICE — ${formatBRL(r.price.fixedInstallment)}/mês (parcela fixa)\n`
      }
      text += `   Total pago: ${formatBRL(r.price ? r.price.totalCost : r.sac.totalCost)}\n\n`
    }
  })
  text += '\n' + 'ℹ️ _Estimativa c/ ajuste de risco. Taxa final depende de análise de crédito e relacionamento com o banco._' + '\n\n'
  text += '---\n\nDeseja falar com um consultor?\n\n1️⃣ Sim, quero contato\n2️⃣ Não, obrigado'
} else {
  text += '⚠️ Não foi possível calcular a simulação agora.\nUm consultor entrará em contato.'
}

return [{ json: { ...routerData, response: text, simulationId: sim?.simulationId } }]

return (async () => {
const router = $('Roteador de Conversa').first().json
let formatted = null
try { formatted = $('Formatar Resultado').first()?.json } catch (e) {}
const data = formatted?.simulationId ? formatted : router

const phone         = data.phone
const phoneNumberId = data.phoneNumberId
const waToken       = $env.WHATSAPP_ACCESS_TOKEN
const waVersion     = $env.WHATSAPP_API_VERSION

// ── Transcript (F-030): log tolerante a falha (não trava o fluxo). ──
const _ctx = this
const _base = router._apiBaseUrl
const _tok  = router._apiToken
async function _logMsg(body) {
  try {
    if (_ctx && _ctx.helpers && typeof _ctx.helpers.httpRequest === 'function' && _base && phone) {
      await _ctx.helpers.httpRequest({
        method: 'POST',
        url: `${_base}/api/conversations/${encodeURIComponent(phone)}/messages`,
        headers: { Authorization: `Bearer ${_tok}` },
        body, json: true, timeout: 6000,
      })
    }
  } catch (e) { /* ignore */ }
}

// Inbound (cliente) — registrado sempre, mesmo com o bot pausado
let _inbound = null
try { _inbound = $('Extrair Mensagem').first().json } catch (e) {}
if (_inbound && _inbound.rawText) {
  await _logMsg({ direction: 'inbound', sender: 'customer', type: 'text', content: _inbound.rawText, waMessageId: _inbound.messageId })
}

// Cliente pediu consultor → marca a conversa como aguardando atendimento humano (fila)
if (router.triggerHandoff) {
  try {
    if (_ctx && _ctx.helpers && typeof _ctx.helpers.httpRequest === 'function' && _base && phone) {
      await _ctx.helpers.httpRequest({ method: 'POST', url: `${_base}/api/conversations/${encodeURIComponent(phone)}/request-human`, headers: { Authorization: `Bearer ${_tok}` }, json: true, timeout: 6000 })
    }
  } catch (e) { /* ignore */ }
  // Criar Lead — tolerante a falha
  try {
    let clientId = null
    try { clientId = $('Buscar Cliente').first()?.json?.id } catch (_) {}
    if (!clientId) { try { clientId = $('Salvar Cliente').first()?.json?.id } catch (_) {} }
    let simId = null
    try { simId = $('Formatar Resultado').first()?.json?.simulationId } catch (_) {}
    const product = router.ctx?.requestedProduct
    if (clientId && _base && phone && _ctx && _ctx.helpers) {
      await _ctx.helpers.httpRequest({
        method: 'POST',
        url: `${_base}/api/leads`,
        headers: { Authorization: `Bearer ${_tok}`, 'Content-Type': 'application/json' },
        body: { clientId, whatsappNumber: phone, ...(simId ? { simulationId: simId } : {}), ...(product ? { notes: `Produto: ${product}` } : {}) },
        json: true, timeout: 6000,
      })
    }
  } catch (e) { /* ignore */ }
}

// Bot pausado (modo humano): não envia resposta automática
if (data.skipReply) return []

let waMessage
if (data.interactive) {
  waMessage = {
    messaging_product: 'whatsapp',
    recipient_type:    'individual',
    to:                phone,
    type:              'interactive',
    interactive:       data.interactive,
  }
} else {
  waMessage = {
    messaging_product: 'whatsapp',
    recipient_type:    'individual',
    to:                phone,
    type:              'text',
    text:              { body: data.response },
  }
}

// Outbound (bot)
const _outText = data.response || (data.interactive && data.interactive.body && data.interactive.body.text) || ''
if (_outText) {
  await _logMsg({ direction: 'outbound', sender: 'bot', type: data.interactive ? 'interactive' : 'text', content: _outText, payload: data.interactive || undefined })
}

return [{
  json: { phone, phoneNumberId, response: data.response, waToken, waVersion, waMessage }
}]
})()
